### 1. useMountedRef Hook Tests
```typescript
describe("useMountedRef", () => {
  it("should return true while component is mounted", () => {
    const { result } = renderHook(() => useMountedRef());
    expect(result.current.current).toBe(true);
    console.log("[TEST] useMountedRef returns true while mounted");
  });

  it("should return false after component unmounts", () => {
    const { result, unmount } = renderHook(() => useMountedRef());
    expect(result.current.current).toBe(true);

    unmount();

    expect(result.current.current).toBe(false);
    console.log("[TEST] useMountedRef returns false after unmount");
  });

  it("should handle rapid mount/unmount cycles", () => {
    for (let i = 0; i < 10; i++) {
      const { result, unmount } = renderHook(() => useMountedRef());
      expect(result.current.current).toBe(true);
      unmount();
      expect(result.current.current).toBe(false);
    }
    console.log("[TEST] useMountedRef handles rapid mount/unmount cycles");
  });
});
```

### 2. WebSocket Provider Unmount Safety
```typescript
describe("WebSocketProvider - unmount safety", () => {
  let mockWebSocket: MockWebSocket;
  let consoleErrorSpy: jest.SpyInstance;

  beforeEach(() => {
    mockWebSocket = new MockWebSocket();
    global.WebSocket = jest.fn(() => mockWebSocket) as any;
    consoleErrorSpy = jest.spyOn(console, "error").mockImplementation();
  });

  afterEach(() => {
    consoleErrorSpy.mockRestore();
  });

  it("should NOT call setState when onopen fires after unmount", async () => {
    const { unmount } = render(
      <WebSocketProvider url="ws://test">
        <TestConsumer />
      </WebSocketProvider>
    );

    // Unmount before connection opens
    unmount();
    console.log("[TEST] Component unmounted before ws.onopen");

    // Simulate WebSocket opening after unmount
    act(() => {
      mockWebSocket.triggerOpen();
    });
    console.log("[TEST] ws.onopen triggered after unmount");

    // Should NOT have React warning
    expect(consoleErrorSpy).not.toHaveBeenCalledWith(
      expect.stringContaining("unmounted component")
    );
    console.log("[TEST] PASS: No React warning for setState on unmounted");
  });

  it("should NOT call setState when onmessage fires after unmount", async () => {
    const { unmount } = render(
      <WebSocketProvider url="ws://test">
        <TestConsumer />
      </WebSocketProvider>
    );

    // Establish connection
    act(() => mockWebSocket.triggerOpen());

    // Unmount
    unmount();
    console.log("[TEST] Component unmounted while connected");

    // Receive message after unmount
    act(() => {
      mockWebSocket.triggerMessage({ type: "update", data: {} });
    });
    console.log("[TEST] ws.onmessage triggered after unmount");

    expect(consoleErrorSpy).not.toHaveBeenCalledWith(
      expect.stringContaining("unmounted component")
    );
  });

  it("should NOT call setState when onerror fires after unmount", async () => {
    const { unmount } = render(
      <WebSocketProvider url="ws://test">
        <TestConsumer />
      </WebSocketProvider>
    );

    unmount();

    act(() => {
      mockWebSocket.triggerError(new Error("Connection failed"));
    });

    expect(consoleErrorSpy).not.toHaveBeenCalledWith(
      expect.stringContaining("unmounted component")
    );
  });

  it("should NOT call setState when onclose fires after unmount", async () => {
    const { unmount } = render(
      <WebSocketProvider url="ws://test">
        <TestConsumer />
      </WebSocketProvider>
    );

    act(() => mockWebSocket.triggerOpen());
    unmount();

    act(() => {
      mockWebSocket.triggerClose({ code: 1000, reason: "Normal close" });
    });

    expect(consoleErrorSpy).not.toHaveBeenCalledWith(
      expect.stringContaining("unmounted component")
    );
    console.log("[TEST] PASS: onclose safe after unmount");
  });
});
