+function MountRefTracker({
+  onRefChange,
+}: {
+  onRefChange: (mounted: boolean) => void;
+}) {
+  const isMounted = useMountedRef();
+
+  useEffect(() => {
+    // Report mount ref value after each render
+    onRefChange(isMounted.current);
