+  const updateAsync = useCallback(async () => {
+    await new Promise((resolve) => setTimeout(resolve, delay));
+
+    // Guard against setState after unmount
+    if (!isMounted.current) {
+      onAttemptSetState?.(true); // Skipped
+      return;
+    }
